#!/bin/bash\n\n# Samadhan - Fix Dependencies Script\n# This script fixes all missing dependencies and resolves common issues\n\nset -e\n\necho \"🔧 Fixing Samadhan Web Dependencies...\"\n\n# Navigate to web directory\ncd web\n\necho \"📦 Installing missing dependencies...\"\n\n# Install react-hot-toast if missing\nif ! npm list react-hot-toast >/dev/null 2>&1; then\n    echo \"Installing react-hot-toast...\"\n    npm install react-hot-toast@^2.4.1\nfi\n\n# Install all dependencies\necho \"📥 Installing all dependencies...\"\nnpm install\n\necho \"🧹 Clearing Next.js cache...\"\nrm -rf .next\n\necho \"🔄 Regenerating types...\"\nnpx convex dev --once || echo \"Convex not running, skipping type generation\"\n\necho \"✅ Dependencies fixed! You can now run:\"\necho \"   npm run dev\"\necho \"   or\"\necho \"   npx convex dev (in another terminal)\"\n"